import numpy as np

class NaiveBayesClassifier:
 def __init__(self):
 self.prior_probabilities = None
 self.conditional_probabilities = None

 def fit(self, X, y):
 # Calculate prior probabilities
 self.prior_probabilities = np.bincount(y) / len(y)

 # Calculate conditional probabilities
 self.conditional_probabilities = np.zeros((X.shape[1], len(np.unique(y))))
 for i in range(X.shape[1]):
 for j in range(len(np.unique(y))):
 self.conditional_probabilities[i, j] = np.mean(X[y == j, i])

 def predict(self, X):
 # Calculate posterior probabilities
 posterior_probabilities = np.zeros((X.shape[0], len(np.unique(y))))
 for i in range(X.shape[0]):
 for j in range(len(np.unique(y))):
 posterior_probabilities[i, j] = np.prod(self.conditional_probabilities[:, j] ** X[i]) * self.prior_probabilities[j]

 # Return predicted class labels
 return np.argmax(posterior_probabilities, axis=1)

#include <stdio.h>

double bayesTheorem(double prior, double likelihood, double evidence) {
 double posterior = (likelihood * prior) / evidence;
 return posterior;
}

int main() {
 double prior = 0.5;
 double likelihood = 0.7;
 double evidence = 0.9;
 double posterior = bayesTheorem(prior, likelihood, evidence);
 printf("Posterior probability: %f\n", posterior);
 return 0;
}
